def get_destination(slug):
    return DESTINATIONS.get(slug)


def get_related_destinations(slug, limit=6):
    dest = DESTINATIONS.get(slug)
    if not dest:
        return []
    return [d for s, d in DESTINATIONS.items() if d['continent'] == dest['continent'] and s != slug][:limit]


def get_destinations_by_continent():
    by_continent = {}
    for slug, dest in DESTINATIONS.items():
        continent = dest['continent']
        if continent not in by_continent:
            by_continent[continent] = []
        by_continent[continent].append(dest)
    return by_continent


def get_all_destination_slugs():
    return list(DESTINATIONS.keys())
